/** @deprecated use RWANDA_SECTORS filtered by province */
export const KIGALI_SECTORS = RWANDA_SECTORS.filter(s => s.province === "Kigali City");
/** @deprecated */
export const KIGALI_DISTRICTS = ["Gasabo", "Kicukiro", "Nyarugenge"];

export function districtsByProvince(): Map<string, string[]> {
  const m = new Map<string, string[]>();
  for (const { province, district } of RWANDA_DISTRICTS) {
    if (!m.has(province)) m.set(province, []);
    m.get(province)!.push(district);
  }
  return m;
}

export function sectorsByDistrict(): Map<string, RwandaSector[]> {
  const m = new Map<string, RwandaSector[]>();
  for (const s of RWANDA_SECTORS) {
    if (!m.has(s.district)) m.set(s.district, []);
    m.get(s.district)!.push(s);
  }
  return m;
}

/** Cells indexed by sector pcode — O(1) lookup in the picker. */
export function cellsBySectorPcode(): Map<string, RwandaCell[]> {
  const m = new Map<string, RwandaCell[]>();
  for (const c of RWANDA_CELLS) {
    if (!m.has(c.sectorPcode)) m.set(c.sectorPcode, []);
    m.get(c.sectorPcode)!.push(c);
  }
  return m;
}

export function findSector(sector: string, district?: string, province?: string): RwandaSector | undefined {
  return RWANDA_SECTORS.find(s =>
    s.sector === sector &&
    (district == null || s.district === district) &&
    (province == null || s.province === province),
  );
}

export function getViewerLocation(): ViewerLocation | null {
  if (typeof window === "undefined") return null;
  try {
    const raw = localStorage.getItem(VIEWER_LOC_KEY);
    return raw ? (JSON.parse(raw) as ViewerLocation) : null;
  } catch { return null; }
}

export function saveViewerLocation(loc: ViewerLocation): void {
  if (typeof window === "undefined") return;
  localStorage.setItem(VIEWER_LOC_KEY, JSON.stringify(loc));
}
